export const meta = { name: 'parallel_primality_checks', description: 'Run independent primality checks for 17 and synthesize surviving evidence.', phases: [{ title: 'Checks' }, { title: 'Synthesis' }] }

phase('Checks')
const checks = await parallel([
  () => agent('Independently determine whether 17 is prime. Show a concise mathematical check by testing divisibility only by primes up to sqrt(17). Return JSON with checker, prime (boolean), and evidence (string).', {
    label: 'trial division',
    tier: 'small',
    schema: {
      type: 'object',
      properties: {
        checker: { type: 'string' },
        prime: { type: 'boolean' },
        evidence: { type: 'string' }
      },
      required: ['checker', 'prime', 'evidence'],
      additionalProperties: false
    }
  }),
  () => agent('Independently check if 17 is prime using a distinct elementary argument: list its possible factor pairs or explain why none exist. Return JSON with checker, prime (boolean), and evidence (string).', {
    label: 'factor pairs',
    tier: 'small',
    schema: {
      type: 'object',
      properties: {
        checker: { type: 'string' },
        prime: { type: 'boolean' },
        evidence: { type: 'string' }
      },
      required: ['checker', 'prime', 'evidence'],
      additionalProperties: false
    }
  })
])

phase('Synthesis')
const surviving = checks.filter(x => x !== null)
const failedChecks = checks.map((x, i) => x === null ? 'checker-' + (i + 1) : null).filter(x => x !== null)
const synthesis = await agent('Synthesize the surviving independent evidence below into the required compact result. The number 17 is prime exactly when the evidence supports it. Preserve accurate evidence, note failed check identifiers separately, and return only JSON matching the schema. Surviving evidence: ' + JSON.stringify(surviving) + '. Failed checks: ' + JSON.stringify(failedChecks) + '.', {
  label: 'evidence synthesis',
  tier: 'big',
  schema: {
    type: 'object',
    properties: {
      prime: { type: 'boolean' },
      evidence: { type: 'array', items: { type: 'string' } },
      failedChecks: { type: 'array', items: { type: 'string' } }
    },
    required: ['prime', 'evidence', 'failedChecks'],
    additionalProperties: false
  }
})

if (synthesis !== null) return synthesis
return { prime: surviving.length > 0 && surviving.every(x => x.prime === true), evidence: surviving.map(x => x.evidence), failedChecks }

